) {
  try {
    const { userId } = await params;
    const sql = getDb();

    const rows = await sql(
      `UPDATE queue SET status = 'completed'
       WHERE user_id = $1::uuid AND status IN ('waiting', 'active')
       RETURNING id, status`,
      [userId]
    );

    if (!rows.length) {
      return NextResponse.json({ error: "No queue entry found" }, { status: 404 });
