export interface ScrapeJob {
  user_id: string;
  user_name: string;
  status: "running" | "completed" | "failed";
  phase: string;
  purchases_found: number;
  started_at: string;
  completed_at: string | null;
  error: string | null;
}

export function getScrapeJobs() {
  return request<ScrapeJob[]>("/admin/scrape-jobs");
}

