     3→import { useEffect, useState, useRef } from "react";
     4→import { getQueueStatus, joinQueue, leaveQueue, QueueInfo } from "@/lib/api";
     5→
     6→interface QueueStatusProps {
     7→  userId: string;
     8→  onBecameActive?: () => void;
     9→  onLeave?: () => void;
    10→}
    11→
    12→export default function QueueStatus({ userId, onBecameActive, onLeave }: QueueStatusProps) {
    13→  const [queue, setQueue] = useState<QueueInfo | null>(null);
    14→  const [error, setError] = useState("");
    15→  const [leaving, setLeaving] = useState(false);
    16→  const firedRef = useRef(false);
    17→
    18→  useEffect(() => {
    19→    let cancelled = false;
    20→    let timer: ReturnType<typeof setInterval>;
    21→
    22→    async function init() {
    23→      try {
    24→        const info = await joinQueue(userId);
    25→        if (!cancelled) setQueue(info);
    26→      } catch (err) {
    27→        if (!cancelled) setError(err instanceof Error ? err.message : "Failed to join queue");
    28→      }
    29→    }
    30→
    31→    init();
    32→
    33→    // Poll every 5 seconds
    34→    timer = setInterval(async () => {
    35→      try {
    36→        const info = await getQueueStatus(userId);
    37→        if (!cancelled) setQueue(info);
    38→      } catch {
    39→        // Ignore polling errors
    40→      }
    41→    }, 5000);
    42→
    43→    return () => {
    44→      cancelled = true;
    45→      clearInterval(timer);
    46→    };
    47→  }, [userId]);
    48→
    49→  // Fire onBecameActive exactly once
    50→  useEffect(() => {
    51→    if (queue?.status === "active" && !firedRef.current && onBecameActive) {
    52→      firedRef.current = true;
    53→      onBecameActive();
    54→    }
    55→  }, [queue?.status, onBecameActive]);
    56→
    57→  async function handleLeave() {
    58→    setLeaving(true);
    59→    try {
    60→      await leaveQueue(userId);
    61→      onLeave?.();
    62→    } catch {
    63→      setLeaving(false);
    64→      setError("Failed to leave queue. Please try again.");
    65→    }
    66→  }
    67→
    68→  if (error) {
    69→    return (
    70→      <div className="text-center text-red-500">
    71→        <p>{error}</p>
    72→      </div>
    73→    );
